"use client";

import { useEffect, useState } from "react";
import { useParams, useRouter } from "next/navigation";
import { ArrowLeft, History, User as UserIcon } from "lucide-react";

import PatientInfoCard from "../../components/PatientInfoCard";
import RecordCard from "../../../patient/components/RecordCard";

export default function DoctorPatientDetailsPage() {
  const params = useParams();
  const router = useRouter();

  const patientId = (params?.patientId || "") as string;

  const [patient, setPatient] = useState<any>(null);
  const [records, setRecords] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const fetchData = async () => {
      if (!patientId) return;

      try {
        setLoading(true);
        setError(null);

        const token = localStorage.getItem("token");

        const [profileRes, historyRes] = await Promise.all([
          fetch(`http://localhost:5000/api/doctor/patient/${patientId}`, {
            headers: {
              Authorization: `Bearer ${token}`,
            },
          }),
          fetch(
            `http://localhost:5000/api/doctor/patient/${patientId}/history`,
            {
              headers: {
                Authorization: `Bearer ${token}`,
              },
            }
          ),
        ]);

        if (!profileRes.ok) {
          const data = await profileRes.json().catch(() => ({}));
          throw new Error(data.message || "Failed to load patient profile");
        }

        if (!historyRes.ok) {
          const data = await historyRes.json().catch(() => ({}));
          throw new Error(data.message || "Failed to load medical history");
        }

        const profileData = await profileRes.json();
        const historyData = await historyRes.json();

        setPatient(profileData);
        setRecords(historyData);
      } catch (err: any) {
        console.error(err);
        setError(err.message || "Something went wrong");
      } finally {
        setLoading(false);
      }
    };

    fetchData();
  }, [patientId]);

  return (
    <div className="min-h-screen bg-slate-900 text-white px-6 py-8">
      <div className="max-w-6xl mx-auto space-y-6">
        {/* Header */}
        <div className="flex items-center justify-between gap-3">
          <div className="flex items-center gap-3">
            <button
              onClick={() => router.back()}
              className="p-2 rounded-lg bg-white/5 border border-white/10 hover:bg-white/10 transition"
            >
              <ArrowLeft className="w-4 h-4" />
            </button>

            <div className="flex items-center gap-3">
              <div className="p-2 rounded-lg bg-indigo-500/20">
                <UserIcon className="w-5 h-5 text-indigo-400" />
              </div>
              <div>
                <h1 className="text-2xl font-bold">Patient Overview</h1>
                <p className="text-gray-400 text-sm">
                  View full profile and complete medical history
                </p>
              </div>
            </div>
          </div>

          {patientId && (
            <span className="text-xs px-3 py-1 rounded-full bg-white/5 border border-white/10 text-gray-300">
              ID: {patientId}
            </span>
          )}
        </div>

        {/* Error */}
        {error && (
          <div className="p-4 rounded-xl bg-red-500/10 border border-red-500/30 text-sm text-red-200">
            {error}
          </div>
        )}

        {/* Loading */}
        {loading && !error && (
          <div className="text-center text-gray-400 mt-10">Loading...</div>
        )}

        {/* Content */}
        {!loading && !error && (
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
            {/* Left: Profile */}
            <div className="lg:col-span-1 space-y-4">
              {patient && <PatientInfoCard patient={patient} />}
            </div>

            {/* Right: History */}
            <div className="lg:col-span-2 space-y-4">
              <div className="flex items-center gap-2 mb-2">
                <div className="p-2 rounded-lg bg-indigo-500/20">
                  <History className="w-5 h-5 text-indigo-400" />
                </div>
                <h2 className="text-lg font-semibold">Medical History</h2>
              </div>

              {records.length === 0 ? (
                <div className="text-sm text-gray-400 mt-4">
                  No medical records found for this patient.
                </div>
              ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  {records.map((record, index) => (
                    <RecordCard key={index} record={record} />
                  ))}
                </div>
              )}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
